declare(strict_types=1);
function visible_contacts_for_picker(): array {return array_values(array_filter(db()->query('SELECT id,first_name,last_name,company FROM contacts WHERE active=1 ORDER BY last_name,first_name')->fetchAll(),fn($c)=>contact_access((int)$c['id'])!=='hidden'));}
if(!function_exists('opportunity_contacts')){function opportunity_contacts(int $opportunityId): array {$s=db()->prepare('SELECT c.* FROM contacts c JOIN opportunity_contacts oc ON oc.contact_id=c.id WHERE oc.opportunity_id=? ORDER BY c.last_name,c.first_name');$s->execute([$opportunityId]);return array_values(array_filter($s->fetchAll(),fn($c)=>contact_access((int)$c['id'])!=='hidden'));}}
if($path==='/events/new'){
 require_permission('events.edit');$contacts=visible_contacts_for_picker();if($method==='POST'){verify_csrf();$type=(string)post('event_type');if(!in_array($type,option_codes('event_type'),true)){flash('error','Choose a valid event type.');redirect('/events/new');}$slides=null;$original=null;if(isset($_FILES['slides'])&&$_FILES['slides']['error']!==UPLOAD_ERR_NO_FILE){$f=$_FILES['slides'];$allowed=['application/pdf'=>'pdf','application/vnd.ms-powerpoint'=>'ppt','application/vnd.openxmlformats-officedocument.presentationml.presentation'=>'pptx'];$mime=(new finfo(FILEINFO_MIME_TYPE))->file($f['tmp_name']);if($f['error']!==UPLOAD_ERR_OK||$f['size']>config('upload_max')||!isset($allowed[$mime])){flash('error','Slides must be a PDF, PPT, or PPTX within the upload limit.');redirect('/events/new');}$slides=bin2hex(random_bytes(20)).'.'.$allowed[$mime];if(!move_uploaded_file($f['tmp_name'],dirname(__DIR__).'/storage/uploads/'.$slides))throw new RuntimeException('Upload failed');$original=basename($f['name']);}db()->prepare('INSERT INTO events(title,event_type,starts_at,presentation_title,abstract,booking_url,conference_url,venue_address,slides_path,slides_original_name,presenter_contact_id,presenter_name,created_by,owner_id) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?)')->execute([trim(post('title')),$type,post('starts_at'),trim(post('presentation_title'))?:null,trim(post('abstract'))?:null,trim(post('booking_url'))?:null,trim(post('conference_url'))?:null,trim(post('venue_address'))?:null,$slides,$original,(int)post('presenter_contact_id')?:null,trim(post('presenter_name'))?:null,user()['id'],user()['id']]);$id=(int)db()->lastInsertId();audit('create','event',$id);redirect('/events/'.$id);}layout('New event',function()use($contacts){?><h1>New event</h1><form class="card" method="post" enctype="multipart/form-data"><input type="hidden" name="_csrf" value="<?=csrf()?>"><div class="form-grid"><label>Event name<input name="title" required></label><label>Type<select name="event_type"><?php foreach(list_options('event_type') as $o):?><option value="<?=$o['code']?>"><?=e($o['label'])?></option><?php endforeach?></select></label><label>Date and time<input type="datetime-local" name="starts_at" required></label><label>Slides<input type="file" name="slides" accept=".pdf,.ppt,.pptx"></label><label>Presentation title<input name="presentation_title"></label><label>Presenter contact<select name="presenter_contact_id"><option value="">Choose contact</option><?php foreach($contacts as $c):?><option value="<?=$c['id']?>"><?=e($c['last_name'].', '.$c['first_name'].' — '.$c['company'])?></option><?php endforeach?></select></label><label>Presenter name <span class="muted">(if not a contact)</span><input name="presenter_name"></label><label>Webinar booking URL<input type="url" name="booking_url"></label><label>Conference URL<input type="url" name="conference_url"></label><label>Conference address<textarea name="venue_address"></textarea></label><label class="full">Abstract<textarea name="abstract" rows="7"></textarea></label></div><button>Save event</button></form><?php });exit;
