if(preg_match('#^/events/(\d+)/delete$#',$path,$m)&&$method==='POST'){
 require_permission('events.edit');verify_csrf();$id=(int)$m[1];$s=db()->prepare('SELECT * FROM events WHERE id=?');$s->execute([$id]);$event=$s->fetch();if(!$event){http_response_code(404);exit;}require_record_edit($event);db()->beginTransaction();try{db()->prepare("UPDATE opportunities SET source_type='other',source_note=CONCAT('Deleted event: ',?),source_event_id=NULL WHERE source_event_id=?")->execute([$event['title'],$id]);audit('delete','event',$id,['title'=>$event['title']]);db()->prepare('DELETE FROM events WHERE id=?')->execute([$id]);db()->commit();if($event['slides_path'])@unlink(dirname(__DIR__).'/storage/uploads/'.basename($event['slides_path']));flash('success','Event deleted.');redirect('/events');}catch(Throwable $e){db()->rollBack();throw $e;}
