if(preg_match('#^/opportunities/(\d+)/edit$#',$path,$m)){
 require_permission('contacts.edit');$id=(int)$m[1];$s=db()->prepare('SELECT * FROM opportunities WHERE id=?');$s->execute([$id]);$o=$s->fetch();if(!$o){http_response_code(404);exit('Opportunity not found');}require_record_edit($o);
