}
if(preg_match('#^/opportunities/(\d+)/(archive|restore)$#',$path,$m)&&$method==='POST'){require_permission('contacts.edit');verify_csrf();$id=(int)$m[1];$s=db()->prepare('SELECT * FROM opportunities WHERE id=?');$s->execute([$id]);$o=$s->fetch();if(!$o){http_response_code(404);exit;}require_record_edit($o);$active=$m[2]==='restore'?1:0;db()->prepare('UPDATE opportunities SET active=? WHERE id=?')->execute([$active,$id]);audit($m[2],'opportunity',$id);flash('success',$active?'Opportunity restored.':'Opportunity archived.');redirect($active?'/opportunities/'.$id:'/opportunities');}
